def fib(n: int) -> int:
    memo = {0: 0, 1: 1}

    def helper(k: int) -> int:
        if k in memo:
            return memo[k]

        # Recursive step with memoization
        memo[k] = helper(k - 1) + helper(k - 2)
        return memo[k]

    return helper(n)

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

